const jwt = require('jsonwebtoken');
const { SECRET_KEY } = require('../services/authService');

const verifyToken = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1]; // Láº¥y token tá»« header
  if (!token) return res.status(403).json({ message: "âŒ Thiáº¿u tháº» bÃ i (Token)!" });

  try {
    const decoded = jwt.verify(token, SECRET_KEY);
    req.user = decoded; // LÆ°u thÃ´ng tin ngÆ°á»i dÃ¹ng vÃ o request
    next();
  } catch (err) {
    res.status(401).json({ message: "âŒ Tháº» bÃ i khÃ´ng há»£p lá»‡ hoáº·c Ä‘Ã£ háº¿t háº¡n!" });
  }
};

const verifyManager = (req, res, next) => {
  verifyToken(req, res, () => {
    if (req.user.role === 'MANAGER' || req.user.role === 'ADMIN') {
      next();
    } else {
      res.status(403).json({ message: "âŒ CÃºt! Chá»©c vá»¥ tháº¥p quÃ¡ khÃ´ng Ä‘Æ°á»£c duyá»‡t Ä‘Æ¡n!" });
    }
  });
};

module.exports = { verifyToken, verifyManager };

