const db = require('./db');

// Láº­p lá»‡nh giao hÃ ng má»›i
const createShipment = async (shipmentCode, factoryManagerId, items) => {
  const receiptRes = await db.query(
    `INSERT INTO factory_shipments (shipment_code, factory_manager_id) VALUES ($1, $2) RETURNING id`,
    [shipmentCode, factoryManagerId]
  );
  const shipmentId = receiptRes.rows[0].id;

  for (let item of items) {
    await db.query(
      `INSERT INTO factory_shipment_details (shipment_id, product_id, expected_qty) VALUES ($1, $2, $3)`,
      [shipmentId, item.productId, item.quantity]
    );
  }
  return shipmentId;
};

// Quáº£n lÃ½ kho duyá»‡t lá»‡nh
const approveShipment = async (shipmentId, warehouseManagerId) => {
  const result = await db.query(
    `UPDATE factory_shipments 
     SET status = 'APPROVED', warehouse_manager_id = $1 
     WHERE id = $2 RETURNING *`,
    [shipmentId, warehouseManagerId]
  );
  return result.rows[0];
};

// Dá»‹ch mÃ£ váº¡ch (SKU) ra thÃ´ng tin sáº£n pháº©m
const getProductBySKU = async (sku) => {
  const result = await db.query('SELECT id, name FROM products WHERE sku = $1', [sku]);
  return result.rows[0];
};

// Cáº­p nháº­t: Cá»© má»—i láº§n quÃ©t lÃ  cá»™ng thÃªm 1 vÃ o cá»™t scanned_qty
const updateScannedQuantity = async (shipmentId, productId) => {
  const result = await db.query(
    `UPDATE factory_shipment_details 
     SET scanned_qty = scanned_qty + 1 
     WHERE shipment_id = $1 AND product_id = $2 
     RETURNING expected_qty, scanned_qty`,
    [shipmentId, productId]
  );
  return result.rows[0];
};

// Ghi nháº­n hÃ ng lá»—i vÃ o sá»• vÃ  tÄƒng biáº¿n Ä‘áº¿m hÃ ng lá»—i lÃªn 1
const recordDefectiveItem = async (shipmentId, productId, reason) => {
  // TÄƒng sá»‘ Ä‘áº¿m hÃ ng lá»—i
  await db.query(
    `UPDATE factory_shipment_details 
     SET defect_qty = defect_qty + 1 
     WHERE shipment_id = $1 AND product_id = $2`,
    [shipmentId, productId]
  );

  // Ghi lÃ½ do vÃ o cuá»‘n sá»•
  await db.query(
    `INSERT INTO return_to_factory_logs (shipment_id, product_id, reason) 
     VALUES ($1, $2, $3)`,
    [shipmentId, productId, reason]
  );
};

module.exports = { createShipment, approveShipment, getProductBySKU, updateScannedQuantity, recordDefectiveItem };

const db = require('./db');

// Láº¥y thÃ´ng tin sáº£n pháº©m Ä‘á»ƒ biáº¿t nÃ³ thuá»™c Khu vá»±c nÃ o
const getProductInfo = async (productId) => {
  const result = await db.query('SELECT * FROM products WHERE id = $1', [productId]);
  return result.rows[0];
};

// TÃ¬m cÃ¡c Bin Ä‘ang trá»‘ng trong Ä‘Ãºng Khu vá»±c Ä‘Ã³
const getEmptyBins = async (zoneCode, neededQty) => {
  // Æ¯u tiÃªn xáº¿p tá»« Táº§ng 1 lÃªn Táº§ng trÃªn, tá»« Ká»‡ 1 Ä‘áº¿n Ká»‡ cuá»‘i cho khoa há»c
  const result = await db.query(
    `SELECT id, location_code FROM locations 
     WHERE zone_code = $1 AND status = 'EMPTY' 
     ORDER BY aisle, rack, shelf, bin LIMIT $2`,
    [zoneCode, neededQty]
  );
  return result.rows;
};

// Thá»±c hiá»‡n lÆ°u Phiáº¿u nháº­p vÃ  cáº¥t hÃ ng vÃ o Bin
const executeInbound = async (userId, receiptCode, productDetails) => {
  // 1. Táº¡o tá» Phiáº¿u Nháº­p
  const receiptRes = await db.query(
    `INSERT INTO inbound_receipts (receipt_code, user_id) VALUES ($1, $2) RETURNING id`,
    [receiptCode, userId]
  );
  const receiptId = receiptRes.rows[0].id;

  // 2. Äi cáº¥t tá»«ng mÃ³n hÃ ng vÃ o Bin
  for (let item of productDetails) {
    for (let bin of item.bins) {
      // Äá»•i tráº¡ng thÃ¡i Bin thÃ nh ÄÃƒ Äáº¦Y vÃ  ghi tÃªn sáº£n pháº©m vÃ o
      await db.query(
        `UPDATE locations SET status = 'FULL', product_id = $1, current_qty = 1 WHERE id = $2`,
        [item.productId, bin.id]
      );

      // Ghi dÃ²ng chi tiáº¿t vÃ o Phiáº¿u Nháº­p
      await db.query(
        `INSERT INTO inbound_details (receipt_id, product_id, location_id, quantity) VALUES ($1, $2, $3, 1)`,
        [receiptId, item.productId, bin.id]
      );
    }
  }
  return receiptId;
};

module.exports = { getProductInfo, getEmptyBins, executeInbound };

const db = require('./db');

const getInventoryList = async () => {
  const query = `
    SELECT 
      p.sku AS "Ma_San_Pham", 
      p.name AS "Ten_San_Pham", 
      COUNT(l.id) AS "So_Luong_Ton",
      json_agg(l.location_code) AS "Danh_Sach_Bin"
    FROM locations l
    JOIN products p ON l.product_id = p.id
    WHERE l.status = 'FULL'
    GROUP BY p.id, p.sku, p.name;
  `;
  const result = await db.query(query);
  return result.rows;
};

module.exports = { getInventoryList };

const db = require('./db');

const insertBulkLocations = async (locations) => {
  // Chuyá»ƒn máº£ng dá»¯ liá»‡u thÃ nh chuá»—i SQL
  const values = locations.map(loc => 
    `('${loc.code}', '${loc.zone}', ${loc.a}, ${loc.r}, ${loc.s}, ${loc.b})`
  ).join(', ');

  // ON CONFLICT DO NOTHING: Náº¿u cháº¡y láº¡i láº§n 2 mÃ  mÃ£ Bin Ä‘Ã£ tá»“n táº¡i thÃ¬ bá» qua, khÃ´ng bÃ¡o lá»—i
  const query = `
    INSERT INTO locations (location_code, zone_code, aisle, rack, shelf, bin) 
    VALUES ${values} 
    ON CONFLICT (location_code) DO NOTHING;
  `;

  await db.query(query);
};

module.exports = { insertBulkLocations };

const db = require('./db');

// TÃ¬m cÃ¡c Bin Ä‘ang chá»©a Ä‘Ãºng mÃ³n hÃ ng mÃ  khÃ¡ch cáº§n láº¥y
const getAvailableBins = async (productId, neededQty) => {
  const result = await db.query(
    `SELECT id, location_code FROM locations 
     WHERE product_id = $1 AND status = 'FULL' 
     ORDER BY aisle, rack, shelf, bin LIMIT $2`,
    [productId, neededQty]
  );
  return result.rows;
};

// Thá»±c hiá»‡n táº¡o Phiáº¿u Xuáº¥t vÃ  láº¥y hÃ ng ra khá»i Bin
const executeOutbound = async (userId, receiptCode, productDetails) => {
  const receiptRes = await db.query(
    `INSERT INTO outbound_receipts (receipt_code, user_id) VALUES ($1, $2) RETURNING id`,
    [receiptCode, userId]
  );
  const receiptId = receiptRes.rows[0].id;

  for (let item of productDetails) {
    for (let bin of item.bins) {
      // Dá»n sáº¡ch Bin: Äá»•i thÃ nh EMPTY, xÃ³a tÃªn sáº£n pháº©m, Ä‘Æ°a sá»‘ lÆ°á»£ng vá» 0
      await db.query(
        `UPDATE locations SET status = 'EMPTY', product_id = NULL, current_qty = 0 WHERE id = $1`,
        [bin.id]
      );

      // Ghi lá»‹ch sá»­ xuáº¥t kho
      await db.query(
        `INSERT INTO outbound_details (receipt_id, product_id, location_id, quantity) VALUES ($1, $2, $3, 1)`,
        [receiptId, item.productId, bin.id]
      );
    }
  }
  return receiptId;
};

module.exports = { getAvailableBins, executeOutbound };

