const locationModel = require('../models/locationModel');

const generateWarehouseLayout = async () => {
  // Cáº¥u hÃ¬nh chuáº©n theo báº£n thiáº¿t káº¿ em cung cáº¥p
  const configs = [
    { category: 'TV', brands: ['SN', 'SS', 'LG', 'TCL'], aisles: 4, racks: 5, shelves: 3, bins: 4 },
    { category: 'TL', brands: ['PNS', 'AQ', 'TSB', 'HTC'], aisles: 4, racks: 5, shelves: 2, bins: 4 },
    { category: 'MG', brands: ['EL', 'LG', 'TSB', 'AQ'], aisles: 4, racks: 5, shelves: 2, bins: 4 },
    { category: 'ML', brands: ['DK', 'PNS', 'CP', 'SP'], aisles: 4, racks: 5, shelves: 3, bins: 3 },
  ];

  let allLocations = [];

  // VÃ²ng láº·p "Ma thuáº­t" táº¡o ra hÃ ng ngÃ n Bin
  for (let config of configs) {
    for (let brand of config.brands) {
      let zone = `${config.category}-${brand}`; // VÃ­ dá»¥: TV-SN

      for (let a = 1; a <= config.aisles; a++) {
        for (let r = 1; r <= config.racks; r++) {
          for (let s = 1; s <= config.shelves; s++) {
            for (let b = 1; b <= config.bins; b++) {
              // GhÃ©p tÃªn mÃ£ Ä‘á»‹nh danh (VÃ­ dá»¥: TV-SN-A1-R2-S3-B4)
              let code = `${zone}-A${a}-R${r}-S${s}-B${b}`;
              allLocations.push({ code, zone, a, r, s, b });
            }
          }
        }
      }
    }
  }

  // Gá»­i máº£ng chá»©a gáº§n 3000 vá»‹ trÃ­ nÃ y xuá»‘ng cho Thá»§ Kho lÆ°u
  await locationModel.insertBulkLocations(allLocations);
  return allLocations.length; // Tráº£ vá» tá»•ng sá»‘ Bin Ä‘Ã£ táº¡o
};

module.exports = { generateWarehouseLayout };

const outboundModel = require('../models/outboundModel');

const createOutboundReceipt = async (userId, items) => {
  let productDetails = [];

  // BÆ¯á»šC 1: Kiá»ƒm tra xem kho cÃ³ Ä‘á»§ hÃ ng Ä‘á»ƒ bÃ¡n khÃ´ng
  for (let item of items) {
    const availableBins = await outboundModel.getAvailableBins(item.productId, item.quantity);

    if (availableBins.length < item.quantity) {
      throw new Error(`KhÃ´ng Ä‘á»§ hÃ ng! Sáº£n pháº©m ID ${item.productId} chá»‰ cÃ²n ${availableBins.length} cÃ¡i trong kho.`);
    }

    productDetails.push({
      productId: item.productId,
      quantity: item.quantity,
      bins: availableBins
    });
  }

  // BÆ¯á»šC 2: Táº¡o mÃ£ phiáº¿u xuáº¥t (VÃ­ dá»¥: PX-20260620-8888)
  const date = new Date();
  const dateString = `${date.getFullYear()}${(date.getMonth()+1).toString().padStart(2, '0')}${date.getDate().toString().padStart(2, '0')}`;
  const randomNum = Math.floor(1000 + Math.random() * 9000);
  const receiptCode = `PX-${dateString}-${randomNum}`;

  // BÆ¯á»šC 3: Ra lá»‡nh cho Thá»§ kho xuáº¥t hÃ ng
  await outboundModel.executeOutbound(userId, receiptCode, productDetails);

  return { receiptCode, details: productDetails };
};

module.exports = { createOutboundReceipt };

const productModel = require('../models/productModel');

const addProduct = async (data) => {
  const { name, category_code, brand_code, size_or_capacity, type_detail, unit, sale_price, image_url } = data;

  // Xá»­ lÃ½ táº¡o mÃ£ SKU
  let skuPrefix = `${category_code}-${brand_code}`;
  if (size_or_capacity) skuPrefix += `-${size_or_capacity}`;

  const currentCount = await productModel.countProductsByPrefix(skuPrefix);
  const sequenceString = (currentCount + 1).toString().padStart(3, '0');
  const finalSKU = `${skuPrefix}-${sequenceString}`;

  // Gá»i Thá»§ Kho Ä‘á»ƒ lÆ°u
  return await productModel.createProduct(
    finalSKU, name, category_code, brand_code, size_or_capacity, type_detail, unit, sale_price, image_url
  );
};

const getProducts = async () => {
  return await productModel.getAllProducts();
};

const editProduct = async (id, data) => {
