// ==========================================
// API ÄÄ‚NG NHáº¬P (Táº¡m thá»i Ä‘á»ƒ á»Ÿ Ä‘Ã¢y, má»‘t ráº£nh dá»i sau)
// ==========================================
app.post('/api/login', async (req, res) => {
  try {
    const { username, password } = req.body;

    const result = await db.query('SELECT * FROM users WHERE username = $1', [username]);
    if (result.rows.length === 0) {
      return res.status(401).json({ success: false, message: 'Sai tÃ i khoáº£n hoáº·c máº­t kháº©u!' });
    }

    const user = result.rows[0];

    const isMatch = await bcrypt.compare(password, user.password_hash);
    if (!isMatch) {
      return res.status(401).json({ success: false, message: 'Sai tÃ i khoáº£n hoáº·c máº­t kháº©u!' });
    }

    const token = jwt.sign(
      { id: user.id, username: user.username, role: user.role },
      process.env.JWT_SECRET,
      { expiresIn: '1d' }
    );

    res.json({
      success: true,
      message: 'ÄÄƒng nháº­p thÃ nh cÃ´ng!',
      token: token,
      user: {
        id: user.id,
        username: user.username,
        full_name: user.full_name,
        role: user.role,
        level: user.level
      }
    });

  } catch (error) {
    console.error('Lá»—i Ä‘Äƒng nháº­p:', error);
    res.status(500).json({ success: false, message: 'Lá»—i mÃ¡y chá»§!' });
  }
});



